class FutureCancellationExceptionTest : TestBase() {

    /**
     * Tests the issue described in https://github.com/Kotlin/kotlinx.coroutines/issues/2456
     *
     * When a future is cancelled before the coroutine throws an exception,
     * the exception should be silently dropped (NOT reported to global exception handler).
     */
    @Test
    fun testFutureCancelledBeforeCoroutineThrows() = runTest {
        expect(1)
        val future = future(Dispatchers.Unconfined) {
            expect(2)
            error("foo") // This exception should be dropped, not trigger global handler
        }
        // Cancel the future before the coroutine body runs
        future.cancel(true)
        expect(3)
        assertTrue(future.isCancelled)
        finish(4)
    }

    /**
     * Tests that exceptions in finally blocks after external cancellation
     * are silently dropped, not reported to global exception handler.
     */
    @Test
    fun testExceptionInFinallyAfterExternalCancellation() = runTest {
        expect(1)
        val future = future(NonCancellable + Dispatchers.Unconfined) {
            try {
                delay(Long.MAX_VALUE)
            } finally {
                expect(2)
                throw TestException() // this exception should be dropped, not go to global handler
            }
        }
        future.cancel(true)
        finish(3)
    }

    /**
     * Tests that when future completes externally via complete() and then
     * an exception occurs, it doesn't trigger global exception handler.
     */
    @Test
    fun testExceptionAfterExternalComplete() = runTest {
        expect(1)
        val future = future(NonCancellable + Dispatchers.Unconfined) {
            try {
                delay(Long.MAX_VALUE)
            } finally {
                expect(2)
                throw TestException() // this exception should be dropped
            }
        }
        future.complete(Unit)
        finish(3)
    }

