     * Stress test to verify that Future.cancel() does not report to
     * CoroutineExceptionHandler, matching Guava's behavior.
     */
    @Test
    fun testFutureDoesNotReportToCoroutineExceptionHandler() = runTest {
        repeat(100) {
            val future = future<Unit>(NonCancellable + Dispatchers.Default) {
                throw TestException("can be lost")
            }
            // Cancel immediately, creating a race
            future.cancel(true)
            // Nothing should be reported to CoroutineExceptionHandler
